import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct WeatherIconIntent: AppIntent {
    static var title: LocalizedStringResource = "Weather Icon"
    @Parameter(title: "Icon Name") var iconName: String
}

struct WeatherIconWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "WeatherIconWidget",
            intent: WeatherIconIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.iconName) {
                    content.add(model)
                }
            }
        }
    }
}

